class CheckpointedAgent:
    def checkpoint(self):
        state = {
            'task': self.current_task,
            'progress': self.progress,
            'context': self.context
        }
        with open('.agent_state.json', 'w') as f:
            json.dump(state, f)

    @classmethod
    def restore(cls):
        with open('.agent_state.json') as f:
            state = json.load(f)
        return cls.from_state(state)
